public Map<NUIForm, List<ActionButton>> getActionButtonsAffectingThisSheet(String apname, String thisPath, int thisSheetIndex, User user, RagicBundle bundle) {
	Map<NUIForm, List<ActionButton>> cahce_affectingForm_affectingButton = new LinkedHashMap<>();
	
	Set<String> checkedPathSheet = new HashSet<>();
	for (java.nio.file.Path nuiPath : com.ragic.s3.nui.helper.Util.getApActiveNUIPathList(apname)) {
        
        String path = "/" + nuiPath.getParent().toFile().getName();
        String fileName = nuiPath.toFile().getName(); 
        int sheetIndex = Encoder.parseInt(fileName.substring(0, fileName.indexOf("_")));
        
        if(path.equals(thisPath) && sheetIndex == thisSheetIndex) continue;
        if(checkedPathSheet.contains(path + "/" + sheetIndex)) continue;
        
        checkedPathSheet.add(path + "/" + sheetIndex);
        
        NUIForm checkForm = AppManager.getFormPage(apname, path, sheetIndex, true);
        if(checkForm == null) continue; // issue#13843
        
        for(ActionButton button: checkForm.getActionButtons().values()) {
        	String autogeneratedButtonName = button.getAutoGeneratedActionButtonFunctionNames();
        	if(autogeneratedButtonName == null) continue;

        	boolean functionFound = false;
        	JSONObject functionParams = null;
        	for(String line: checkForm.getSheetscope().split("\n")) {
        		line = line.trim();
        		if(functionFound) {
        			if(line.startsWith("{") && line.endsWith("}")) {
        				try {
        					functionParams = new JSONObject(line);
        				} catch(Exception ignored) {
        				}
        				break;
        			}
        		} else {
                    if(line.startsWith("function " + autogeneratedButtonName + "(")) functionFound = true;
                    continue;
        		}
        	}
        	if(functionParams == null) continue;
        	WorkflowActionType type = WorkflowActionHandlerFactory.getWorkflowActionType(autogeneratedButtonName);
        	if(type == null) continue;
        	
        	WorkflowActionHandlerProxy handlerProxy = new WorkflowActionHandlerProxy(apname, type, WorkflowActionStatus.INIT, user, bundle, new ActionButtonTrigger());
        	if(!handlerProxy.checkIfAffectingForm(functionParams, thisPath, thisSheetIndex)) continue;
        	
        	List<ActionButton> affectingButtons = cahce_affectingForm_affectingButton.get(checkForm);
        	if(affectingButtons == null) {
        		affectingButtons = new ArrayList<>();
        		cahce_affectingForm_affectingButton.put(checkForm, affectingButtons);
        	}
        	affectingButtons.add(button);
        }
    }

    return cahce_affectingForm_affectingButton;
}

